// src/pages/RegisterManageSub1Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx';

import './RegisterManageSub1Page.css';

function RegisterManageSub1Page() {
  const [woods, setWoods] = useState([]);
  const [filter, setFilter] = useState('');
  const [selectedProvince, setSelectedProvince] = useState('');
  const [selectedCommune, setSelectedCommune] = useState('');
  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [selectedLoaiCoSoDangKy] = useState('Đăng ký cơ sở kinh doanh, chế biến gỗ');
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  const [selectedTrangThai, setSelectedTrangThai] = useState('');
  const [selectedLoaiHinhCheBienGo, setSelectedLoaiHinhCheBienGo] = useState('');
  const [selectedNguonGocGo, setSelectedNguonGocGo] = useState('');

  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  const [uniqueCommunes, setUniqueCommunes] = useState([]);
  const [uniqueSpecies, setUniqueSpecies] = useState([]);
  const [uniqueNganhNgheKinhDoanhGo, setUniqueNganhNgheKinhDoanhGo] = useState([]);
  const [uniqueTrangThai, setUniqueTrangThai] = useState([]);
  const [uniqueLoaiHinhCheBienGo, setUniqueLoaiHinhCheBienGo] = useState([]);
  const [uniqueNguonGocGo, setUniqueNguonGocGo] = useState([]);

  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const initialColumnsConfig = {
    tinhThanhPho: { id: 'tinhThanhPho', label: 'Tỉnh (TP)', visible: true, minWidth: '100px' },
    xaPhuong: { id: 'xaPhuong', label: 'Xã (Phường)', visible: true, minWidth: '100px' },
    diaChiCoSo: { id: 'diaChiCoSo', label: 'Địa chỉ cơ sở', visible: true, minWidth: '220px' },
    tenCoSo: { id: 'tenCoSo', label: 'Tên cơ sở', visible: true, minWidth: '180px' },
    vido: { id: 'vido', label: 'Vĩ độ', visible: true, minWidth: '80px' },
    kinhdo: { id: 'kinhdo', label: 'Kinh độ', visible: true, minWidth: '80px' },
    ngayThanhLap: { id: 'ngayThanhLap', label: 'Ngày thành lập', visible: true, minWidth: '100px' },
    giayPhepKinhDoanh: { id: 'giayPhepKinhDoanh', label: 'Số GPKD', visible: true, minWidth: '100px' },
    tenNguoiDaiDien: { id: 'tenNguoiDaiDien', label: 'Người đại diện', visible: true, minWidth: '150px' },
    namSinh: { id: 'namSinh', label: 'Năm sinh', visible: true, minWidth: '80px' },
    soCCCD: { id: 'soCCCD', label: 'Số CCCD/Hộ chiếu', visible: true, minWidth: '120px' },
    ngayCapCCCD: { id: 'ngayCapCCCD', label: 'Ngày cấp CCCD', visible: true, minWidth: '100px' },
    noiCapCCCD: { id: 'noiCapCCCD', label: 'Nơi cấp CCCD', visible: true, minWidth: '120px' },
    soDienThoaiNguoiDaiDien: { id: 'soDienThoaiNguoiDaiDien', label: 'SĐT Người đại diện', visible: true, minWidth: '120px' },
    diaChiNguoiDaiDien: { id: 'diaChiNguoiDaiDien', label: 'Địa chỉ Người đại diện', visible: true, minWidth: '180px' },
    loaiHinhKinhDoanhGo: { id: 'loaiHinhKinhDoanhGo', label: 'Loại hình KD gỗ', visible: false, minWidth: '120px' },
    nganhNgheKinhDoanhGo: { id: 'nganhNgheKinhDoanhGo', label: 'Ngành nghề KD gỗ', visible: false, minWidth: '120px' },
    khoiLuong: { id: 'khoiLuong', label: 'Khối lượng', visible: true, minWidth: '80px' },
    tenLamSan: { id: 'tenLamSan', label: 'Tên lâm sản', visible: true, minWidth: '150px' },
    tenKhoaHoc: { id: 'tenKhoaHoc', label: 'Tên khoa học', visible: true, minWidth: '180px' },
    loaiHinhCheBienGo: { id: 'loaiHinhCheBienGo', label: 'Loại hình chế biến', visible: false, minWidth: '120px' },
    nguonGocGo: { id: 'nguonGocGo', label: 'Nguồn gốc gỗ', visible: false, minWidth: '120px' },
    trangThai: { id: 'trangThai', label: 'Trạng thái', visible: true, minWidth: '100px' },
    ghiChu: { id: 'ghiChu', label: 'Ghi chú', visible: false, minWidth: '200px' },
    actions: { id: 'actions', label: '🛠️', visible: true, width: '175px', minWidth: '175px', maxWidth: '175px' },
  };

  const [columns, setColumns] = useState(initialColumnsConfig);
  const [showColumnOptions, setShowColumnOptions] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15);

  useEffect(() => {
    try {
      const savedColumns = localStorage.getItem('tableColumnsVisibility_WoodBusiness');
      if (savedColumns) {
        const parsedSavedColumns = JSON.parse(savedColumns);
        const mergedColumns = Object.keys(initialColumnsConfig).reduce((acc, key) => {
          const savedCol = parsedSavedColumns.find(sCol => sCol.id === key);
          acc[key] = savedCol ? { ...initialColumnsConfig[key], visible: savedCol.visible } : initialColumnsConfig[key];
          return acc;
        }, {});
        setColumns(mergedColumns);
      }
    } catch (error) {
      console.error("Lỗi khi tải trạng thái cột:", error);
      setColumns(initialColumnsConfig);
    }
  }, []);

  useEffect(() => {
    try {
      const columnsToSave = Object.keys(columns).map(key => ({ id: key, visible: columns[key].visible }));
      localStorage.setItem('tableColumnsVisibility_WoodBusiness', JSON.stringify(columnsToSave));
    } catch (error) {
      console.error("Lỗi khi lưu trạng thái cột:", error);
    }
  }, [columns]);

  useEffect(() => {
    const fetchWoodBusinesses = async () => {
      try {
        const params = { farmType: selectedLoaiCoSoDangKy };
        if (selectedTrangThai) params.trangThai = selectedTrangThai;

        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: { Authorization: `Bearer ${token}` },
          params: params
        });

        const fetchedData = response.data.docs || [];
        setWoods(fetchedData);

        setUniqueProvinces([...new Set(fetchedData.map(f => f.tinhThanhPho).filter(Boolean))].sort());
        setUniqueCommunes([...new Set(fetchedData.map(f => f.xaPhuong).filter(Boolean))].sort());
        setUniqueSpecies([...new Set(fetchedData.map(f => f.tenLamSan).filter(Boolean))].sort());
        setUniqueNganhNgheKinhDoanhGo([...new Set(fetchedData.map(f => f.nganhNgheKinhDoanhGo).filter(Boolean))].sort());
        setUniqueTrangThai([...new Set(fetchedData.map(f => f.trangThai).filter(Boolean))].sort());
        setUniqueLoaiHinhCheBienGo([...new Set(fetchedData.map(f => f.loaiHinhCheBienGo).filter(Boolean))].sort());
        setUniqueNguonGocGo([...new Set(fetchedData.map(f => f.nguonGocGo).filter(Boolean))].sort());

      } catch (error) {
        console.error('Lỗi khi lấy danh sách cơ sở:', error);
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
        setWoods([]);
      }
    };

    if (token) {
      fetchWoodBusinesses();
    } else {
      navigate('/');
    }
  }, [token, navigate, selectedLoaiCoSoDangKy, selectedTrangThai]);

  const handleDelete = async (id) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa cơ sở này?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setWoods(woods.filter(f => f._id !== id));
      } catch (error) {
        console.error('Lỗi khi xóa cơ sở:', error);
      }
    }
  };

  const handleEdit = (id) => navigate(`/edit-wood-business/${id}`);
  const handleNavigateToWoodDetail = (id) => navigate(`/admin/woods/${id}`);

  const filteredWoods = woods.filter(f => {
    const generalMatch = (
      (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.soCCCD || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tenLamSan || '').toLowerCase().includes(filter.toLowerCase())
    );

    const provinceMatch = selectedProvince ? (f.tinhThanhPho === selectedProvince) : true;
    const communeMatch = selectedCommune ? (f.xaPhuong === selectedCommune) : true;
    const speciesMatch = selectedSpecies ? (f.tenLamSan === selectedSpecies) : true;
    const nganhNgheKinhDoanhGoMatch = selectedNganhNgheKinhDoanhGo ? (f.nganhNgheKinhDoanhGo === selectedNganhNgheKinhDoanhGo) : true;
    const trangThaiMatch = selectedTrangThai ? (f.trangThai === selectedTrangThai) : true;
    const loaiHinhCheBienGoMatch = selectedLoaiHinhCheBienGo ? (f.loaiHinhCheBienGo === selectedLoaiHinhCheBienGo) : true;
    const nguonGocGoMatch = selectedNguonGocGo ? (f.nguonGocGo === selectedNguonGocGo) : true;

    return generalMatch && provinceMatch && communeMatch && speciesMatch && nganhNgheKinhDoanhGoMatch && trangThaiMatch && loaiHinhCheBienGoMatch && nguonGocGoMatch;
  });

  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredWoods.slice(indexOfFirstItem, indexOfLastItem);
  const totalPages = Math.ceil(filteredWoods.length / itemsPerPage);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);
  const nextPage = () => { if (currentPage < totalPages) setCurrentPage(currentPage + 1); };
  const prevPage = () => { if (currentPage > 1) setCurrentPage(currentPage - 1); };

  const handleColumnToggle = (columnKey) => {
    setColumns(prev => ({ ...prev, [columnKey]: { ...prev[columnKey], visible: !prev[columnKey].visible } }));
  };
  const handleSelectAllColumns = () => {
    setColumns(prev => {
      const newCols = { ...prev };
      for (const key in newCols) newCols[key].visible = true;
      return newCols;
    });
  };
  const handleDeselectAllColumns = () => {
    setColumns(prev => {
      const newCols = { ...prev };
      for (const key in newCols) if (key !== 'actions') newCols[key].visible = false;
      return newCols;
    });
  };

  const handleExportExcel = () => {
    const columnsToExport = Object.values(columns).filter(col => col.visible && col.id !== 'actions');
    const dataToExport = filteredWoods.map(item => {
      const rowData = {};
      columnsToExport.forEach(col => {
        let value = item[col.id];
        if (['ngayThanhLap', 'ngayCapCCCD'].includes(col.id)) value = value ? new Date(value).toLocaleDateString() : '';
        if (col.id === 'loaiDongVatRung' && Array.isArray(value)) value = value.map(s => s.tenLamSan).join(', ');
        rowData[col.label] = value;
      });
      return rowData;
    });
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "DanhSachCoSoKinhDoanhGo");
    XLSX.writeFile(wb, "DanhSachCoSoKinhDoanhGo.xlsx");
  };

  return (
    <div className="farm-list-container">
      <h2>📋 Danh sách cơ sở kinh doanh, chế biến gỗ</h2>

      <div className="filter-container">
        <input type="text" placeholder="🔍 Tìm kiếm chung..." value={filter} onChange={e => setFilter(e.target.value)} />
        <select value={selectedProvince} onChange={e => setSelectedProvince(e.target.value)}>
          <option value="">Tất cả Tỉnh (TP)</option>
          {uniqueProvinces.map(p => (<option key={p} value={p}>{p}</option>))}
        </select>
        <select value={selectedCommune} onChange={e => setSelectedCommune(e.target.value)}>
          <option value="">Tất cả Xã (Phường)</option>
          {uniqueCommunes.map(c => (<option key={c} value={c}>{c}</option>))}
        </select>
        <select value={selectedSpecies} onChange={e => setSelectedSpecies(e.target.value)}>
          <option value="">Tất cả Tên lâm sản</option>
          {uniqueSpecies.map(s => (<option key={s} value={s}>{s}</option>))}
        </select>
        <select value={selectedNganhNgheKinhDoanhGo} onChange={e => setSelectedNganhNgheKinhDoanhGo(e.target.value)}>
          <option value="">Tất cả Ngành nghề KD</option>
          {uniqueNganhNgheKinhDoanhGo.map(n => (<option key={n} value={n}>{n}</option>))}
        </select>
        <select value={selectedLoaiHinhCheBienGo} onChange={e => setSelectedLoaiHinhCheBienGo(e.target.value)}>
          <option value="">Tất cả Loại hình chế biến</option>
          {uniqueLoaiHinhCheBienGo.map(l => (<option key={l} value={l}>{l}</option>))}
        </select>
        <select value={selectedNguonGocGo} onChange={e => setSelectedNguonGocGo(e.target.value)}>
          <option value="">Tất cả Nguồn gốc</option>
          {uniqueNguonGocGo.map(n => (<option key={n} value={n}>{n}</option>))}
        </select>
        <select value={selectedTrangThai} onChange={e => setSelectedTrangThai(e.target.value)}>
          <option value="">Tất cả Trạng thái</option>
          {uniqueTrangThai.map(s => (<option key={s} value={s}>{s}</option>))}
        </select>
        <button onClick={() => setShowColumnOptions(!showColumnOptions)}>{showColumnOptions ? 'Ẩn cột' : 'Hiện, ẩn cột'}</button>
        <button onClick={handleExportExcel} className="export-excel-button">Xuất Excel</button>
      </div>

      {showColumnOptions && (
        <div className="column-options-container">
          <h3>Chọn cột hiển thị:</h3>
          <div className="column-options-grid">
            {Object.keys(columns).map(key => (
              <label key={key}>
                <input type="checkbox" checked={columns[key].visible} onChange={() => handleColumnToggle(key)} /> {columns[key].label}
              </label>
            ))}
          </div>
          <div className="column-control-buttons">
            <button onClick={handleSelectAllColumns} className="select-all-columns-button">Chọn tất cả</button>
            <button onClick={handleDeselectAllColumns} className="select-all-columns-button">Bỏ chọn tất cả</button>
          </div>
        </div>
      )}

      {currentItems.length > 0 ? (
        <table border="1" cellPadding="8" className="table-auto w-full border-collapse">
          <thead>
            <tr>
              {Object.values(columns).map(col => col.visible && (
                <th key={col.id} style={{ minWidth: col.minWidth, width: col.minWidth }}>{col.label}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {currentItems.map((item) => (
              <tr key={item._id}>
                {Object.values(columns).map(col => col.visible && (
                  <td key={col.id}>
                    {col.id === 'actions' ? (
                      <div className="action-buttons-cell">
                        <button onClick={() => handleNavigateToWoodDetail(item._id)} className="action-button view-button">Nhập, xuất</button>{' '}
                        <button onClick={() => handleEdit(item._id)} className="action-button edit-button">✏️</button>{' '}
                        <button onClick={() => handleDelete(item._id)} className="action-button delete-button">🗑️</button>
                      </div>
                    ) : (
                      ['ngayThanhLap', 'ngayCapCCCD'].includes(col.id) ? (item[col.id] ? new Date(item[col.id]).toLocaleDateString() : '') : item[col.id]
                    )}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      ) : (
        <p>Không có cơ sở nào phù hợp với bộ lọc.</p>
      )}

      {filteredWoods.length > 0 && (
        <div className="pagination-container">
          <div className="pagination-info">
            {indexOfFirstItem + 1} - {Math.min(indexOfLastItem, filteredWoods.length)} / {filteredWoods.length} bản ghi
          </div>
          <div className="pagination-controls">
            <button onClick={prevPage} disabled={currentPage === 1}>«</button>
            {Array.from({ length: totalPages }, (_, i) => (
              <button key={i + 1} onClick={() => paginate(i + 1)} className={currentPage === i + 1 ? 'active' : ''}>{i + 1}</button>
            ))}
            <button onClick={nextPage} disabled={currentPage === totalPages}>»</button>
          </div>
          <div className="items-per-page">
            <select value={itemsPerPage} onChange={(e) => {
              setItemsPerPage(Number(e.target.value));
              setCurrentPage(1);
            }}>
              <option value="5">5 / trang</option>
              <option value="10">10 / trang</option>
              <option value="15">15 / trang</option>
              <option value="20">20 / trang</option>
              <option value="50">50 / trang</option>
            </select>
          </div>
        </div>
      )}
    </div>
  );
}

export default RegisterManageSub1Page;
